```cpp
#include<bits/stdc++.h>
using namespace std;

pair<double,int> getMaxTime(vector<int> &pos, vector<int> &speed, int destination) {
    //once we have picked a destination for all drivers to reach, 
    //find the slowest driver to come to that position 
    //and which direction is that driver
    int maxTime = INT_MIN;
    pair<double,int> res;
    for(int i=0; i<pos.size(); i++) {
        double time = (double)abs(destination - pos[i])/(double)speed[i];
        if(maxTime < time) {
            maxTime = time;
            res.first = time;
            res.second = destination - pos[i] < 0 ? 1 : -1; //1 for right, -1 for left
        }
    }

    return res;
}

int getMinTime(vector<int> &pos, vector<int> &speed, double &minTime, int left, int right) {

    int optimalPos = -1;
    while(left < right) {
        int mid = (left+right)/2;
        pair<double,int> res = getMaxTime(pos, speed, mid);

        if(minTime > res.first) {
            // cout << "optimalPos: " << mid << ' ' << "minTime: " << res.first << '\n';
            minTime = res.first;
            optimalPos = mid;
        }

        if(res.second == -1) {
            //if the slowest driver is in left direction, moving to right will make that driver even late, so
            //we move towards left
            right = mid;
        } else {
            //with same above reasoning, move to right
            left = mid+1;
        }
    }

    return optimalPos;
}

int main() {
    int drivers;
    cin >> drivers;
    vector<int> position;
    vector<int> speed;

    int pos_i, speed_i;
    int leftMostPos = INT_MAX;
    int rightMostPos = INT_MIN;
    for(int i=0; i<drivers; i++) {  
        cin >> pos_i >> speed_i;
        position.push_back(pos_i);
        speed.push_back(speed_i);
        leftMostPos = min(leftMostPos, pos_i);
        rightMostPos = max(rightMostPos, pos_i);
    }

    double minTime = DBL_MAX;
    int optimalPos = getMinTime(position, speed, minTime, leftMostPos, rightMostPos);
    cout << "optimalPos: " << optimalPos << ' ' << "minTime: " << minTime << '\n';
    return 0;
}

